FUNCTION AnalogScale : REAL
VAR_INPUT
    RawValue : INT;
    RawMin   : INT;
    RawMax   : INT;
    EngMin   : REAL;
    EngMax   : REAL;
END_VAR
VAR
    tmp : REAL;
END_VAR

IF RawValue <= RawMin THEN
    AnalogScale := EngMin;
ELSIF RawValue >= RawMax THEN
    AnalogScale := EngMax;
ELSE
    tmp := INT_TO_REAL(RawValue - RawMin) / INT_TO_REAL(RawMax - RawMin);
    AnalogScale := EngMin + tmp * (EngMax - EngMin);
END_IF;
END_FUNCTION

prompt:
Резервуар R-101, датчик уровня UL-101 (AI 0..27648 → 0..100%).

Реализуй PROGRAM TankLevelMonitor.

Входы:
  RawLevel : INT;
  HighAlarmSP : REAL := 85.0;
  LowAlarmSP  : REAL := 15.0;
  Hysteresis  : REAL := 2.0.

Выходы:
  LevelPct : REAL;
  HighAlarm : BOOL;
  LowAlarm  : BOOL.

LevelPct = RawLevel / 276.48 (проценты).
HighAlarm с гистерезисом: включить при LevelPct >= HighAlarmSP, выключить при LevelPct < HighAlarmSP - Hysteresis.
LowAlarm: включить при LevelPct <= LowAlarmSP, выключить при LevelPct > LowAlarmSP + Hysteresis.

code:
PROGRAM TankLevelMonitor
VAR_INPUT
    RawLevel    : INT;
    HighAlarmSP : REAL := 85.0;
    LowAlarmSP  : REAL := 15.0;
    Hysteresis  : REAL := 2.0;
END_VAR
VAR_OUTPUT
    LevelPct  : REAL;
    HighAlarm : BOOL;
    LowAlarm  : BOOL;
END_VAR

LevelPct := INT_TO_REAL(RawLevel) / 276.48;

IF LevelPct >= HighAlarmSP THEN
    HighAlarm := TRUE;
ELSIF LevelPct < (HighAlarmSP - Hysteresis) THEN
    HighAlarm := FALSE;
END_IF;

IF LevelPct <= LowAlarmSP THEN
    LowAlarm := TRUE;
ELSIF LevelPct > (LowAlarmSP + Hysteresis) THEN
    LowAlarm := FALSE;
END_IF;
END_PROGRAM

PROGRAM MotorStarDelta
VAR_INPUT
    Start_btn : BOOL;
    Stop_btn  : BOOL;
    Overload  : BOOL;
END_VAR
VAR_OUTPUT
    Main_Contactor  : BOOL;
    Star_Contactor  : BOOL;
    Delta_Contactor : BOOL;
    Fault           : BOOL;
END_VAR
VAR
    StartTrig       : R_TRIG;
    StarTimer       : TON;
    SeqActive       : BOOL := FALSE;
    SwitchedToDelta : BOOL := FALSE;
END_VAR

StartTrig(CLK := Start_btn);

IF StartTrig.Q AND NOT Stop_btn AND NOT Overload THEN
    SeqActive := TRUE;
    SwitchedToDelta := FALSE;
END_IF;

IF Stop_btn OR Overload THEN
    SeqActive := FALSE;
    SwitchedToDelta := FALSE;
END_IF;

StarTimer(IN := SeqActive AND NOT SwitchedToDelta, PT := T#3s);

IF StarTimer.Q AND SeqActive AND NOT SwitchedToDelta THEN
    SwitchedToDelta := TRUE;
END_IF;

Main_Contactor := SeqActive;
Star_Contactor := SeqActive AND NOT SwitchedToDelta;
Delta_Contactor := SeqActive AND SwitchedToDelta;
Fault := Overload;
END_PROGRAM

TYPE ConveyorState : (ST_IDLE, ST_RUNNING, ST_REJECTING, ST_FAULT);
END_TYPE

PROGRAM SortingConveyor
VAR_INPUT
    StartCmd      : BOOL;
    SensorPresent : BOOL;
    SensorDefect  : BOOL;
    EStop         : BOOL;
END_VAR
VAR_OUTPUT
    MotorRun        : BOOL;
    RejectSolenoid  : BOOL;
END_VAR
VAR
    State       : ConveyorState := ST_IDLE;
    RejectTimer : TON;
END_VAR

RejectTimer(PT := T#500ms);

CASE State OF
    ST_IDLE:
        MotorRun := FALSE;
        RejectSolenoid := FALSE;
        IF StartCmd AND NOT EStop THEN
            State := ST_RUNNING;
        END_IF;

    ST_RUNNING:
        MotorRun := TRUE;
        RejectSolenoid := FALSE;
        IF EStop THEN
            State := ST_FAULT;
        ELSIF SensorPresent AND SensorDefect THEN
            State := ST_REJECTING;
            RejectTimer(IN := TRUE);
        END_IF;

    ST_REJECTING:
        RejectSolenoid := TRUE;
        IF RejectTimer.Q THEN
            RejectTimer(IN := FALSE);
            State := ST_RUNNING;
        END_IF;

    ST_FAULT:
        MotorRun := FALSE;
        RejectSolenoid := FALSE;
        IF NOT EStop THEN
            State := ST_IDLE;
        END_IF;
END_CASE;
END_PROGRAM

prompt:
Контур TIC-401: поддержание температуры в реакторе.

Реализуй FUNCTION_BLOCK PID_Temperature.

Входы:
  Enable : BOOL;
  Setpoint, ProcessValue : REAL;
  Kp : REAL := 2.0;
  Ki : REAL := 0.05;
  Kd : REAL := 0.0;
  CycleTime : TIME := T#100ms.

Выход: Output : REAL (0..100 % на клапан).

При Enable=FALSE: Output=0, сброс интегратора.
При Enable=TRUE: дискретный PID с Ts = TIME_TO_REAL(CycleTime).
Output ограничить 0..100.

code:
FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    Enable       : BOOL;
    Setpoint     : REAL;
    ProcessValue : REAL;
    Kp           : REAL := 2.0;
    Ki           : REAL := 0.05;
    Kd           : REAL := 0.0;
    CycleTime    : TIME := T#100ms;
END_VAR
VAR_OUTPUT
    Output : REAL;
END_VAR
VAR
    Err      : REAL;
    Integral : REAL := 0.0;
    PrevErr  : REAL := 0.0;
    Deriv    : REAL;
    Ts       : REAL;
    RawOut   : REAL;
END_VAR

Ts := TIME_TO_REAL(CycleTime);

IF NOT Enable THEN
    Output := 0.0;
    Integral := 0.0;
    PrevErr := 0.0;
ELSE
    Err := Setpoint - ProcessValue;
    Integral := Integral + Err * Ts;
    Deriv := (Err - PrevErr) / Ts;
    RawOut := Kp * Err + Ki * Integral + Kd * Deriv;

    IF RawOut > 100.0 THEN
        Output := 100.0;
    ELSIF RawOut < 0.0 THEN
        Output := 0.0;
    ELSE
        Output := RawOut;
    END_IF;

    PrevErr := Err;
END_IF;
END_FUNCTION_BLOCK

prompt:
Станция перекачки WW-501: два насоса P1 и P2, работа по уровню в приёмной камере.

Реализуй PROGRAM PumpLeadLag.

Входы:
  LevelLow : BOOL — уровень ниже SP, требуется подпитка;
  LevelHigh : BOOL — уровень выше SP, насосы можно остановить;
  Pump1Fault, Pump2Fault : BOOL;
  ManualMode : BOOL;
  ManualP1Run, ManualP2Run : BOOL.

Выходы: P1Run, P2Run : BOOL.

Авторежим: при LevelLow включить ведущий насос (LeadPump=1 → P1, иначе P2). При LevelHigh оба OFF.
При аварии насоса переключить LeadPump на исправный.
Ручной режим: P1Run=ManualP1Run, P2Run=ManualP2Run.
LeadPump : INT (1 или 2) хранить между циклами.

code:
PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow    : BOOL;
    LevelHigh   : BOOL;
    Pump1Fault  : BOOL;
    Pump2Fault  : BOOL;
    ManualMode  : BOOL;
    ManualP1Run : BOOL;
    ManualP2Run : BOOL;
END_VAR
VAR_OUTPUT
    P1Run : BOOL;
    P2Run : BOOL;
END_VAR
VAR
    LeadPump : INT := 1;
END_VAR

IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    IF Pump1Fault AND NOT Pump2Fault THEN
        LeadPump := 2;
    ELSIF Pump2Fault AND NOT Pump1Fault THEN
        LeadPump := 1;
    END_IF;

    P1Run := FALSE;
    P2Run := FALSE;

    IF LevelLow AND NOT LevelHigh THEN
        IF LeadPump = 1 AND NOT Pump1Fault THEN
            P1Run := TRUE;
        ELSIF LeadPump = 2 AND NOT Pump2Fault THEN
            P2Run := TRUE;
        ELSIF NOT Pump1Fault THEN
            P1Run := TRUE;
            LeadPump := 1;
        ELSIF NOT Pump2Fault THEN
            P2Run := TRUE;
            LeadPump := 2;
        END_IF;
    END_IF;
END_IF;
END_PROGRAM

prompt:
Блок дозирования BD-601: последовательное открытие клапанов V1 → V2 → V3 с выдержками.

Реализуй PROGRAM BatchDoseSequence.

Входы: StartSeq (BOOL), Abort (BOOL).
Выходы: Valve1, Valve2, Valve3 (BOOL), SeqDone (BOOL), SeqActive (BOOL).

Шаги (CASE Step : INT):
  0 — ожидание StartSeq;
  1 — Valve1 ON, TON 2 s → шаг 2;
  2 — Valve2 ON, TON 3 s → шаг 3;
  3 — Valve3 ON, TON 1 s → шаг 4;
  4 — все OFF, SeqDone=TRUE.
Abort в любой момент: сброс в шаг 0, все клапаны OFF.
SeqActive TRUE на шагах 1..3.

code:
PROGRAM BatchDoseSequence
VAR_INPUT
    StartSeq : BOOL;
    Abort    : BOOL;
END_VAR
VAR_OUTPUT
    Valve1   : BOOL;
    Valve2   : BOOL;
    Valve3   : BOOL;
    SeqDone  : BOOL;
    SeqActive : BOOL;
END_VAR
VAR
    Step  : INT := 0;
    Timer : TON;
END_VAR

IF Abort THEN
    Step := 0;
    Valve1 := FALSE;
    Valve2 := FALSE;
    Valve3 := FALSE;
    SeqDone := FALSE;
    SeqActive := FALSE;
    Timer(IN := FALSE);
ELSE
    SeqActive := (Step >= 1) AND (Step <= 3);
    SeqDone := (Step = 4);

    CASE Step OF
        0:
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            SeqDone := FALSE;
            IF StartSeq THEN
                Step := 1;
            END_IF;

        1:
            Valve1 := TRUE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            Timer(IN := TRUE, PT := T#2s);
            IF Timer.Q THEN
                Timer(IN := FALSE);
                Step := 2;
            END_IF;

        2:
            Valve1 := FALSE;
            Valve2 := TRUE;
            Valve3 := FALSE;
            Timer(IN := TRUE, PT := T#3s);
            IF Timer.Q THEN
                Timer(IN := FALSE);
                Step := 3;
            END_IF;

        3:
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := TRUE;
            Timer(IN := TRUE, PT := T#1s);
            IF Timer.Q THEN
                Timer(IN := FALSE);
                Step := 4;
            END_IF;

        4:
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := FALSE;
    END_CASE;
END_IF;
END_PROGRAM

PROGRAM SafetyInterlock
VAR_INPUT
    EStopOK     : BOOL;
    GuardClosed : BOOL;
    ResetPB     : BOOL;
END_VAR
VAR_OUTPUT
    MachineEnable : BOOL;
    SafetyFault   : BOOL;
END_VAR
VAR
    ResetEdge : R_TRIG;
END_VAR

ResetEdge(CLK := ResetPB);

IF NOT EStopOK OR NOT GuardClosed THEN
    SafetyFault := TRUE;
END_IF;

IF ResetEdge.Q AND EStopOK AND GuardClosed THEN
    SafetyFault := FALSE;
END_IF;

MachineEnable := (NOT SafetyFault) AND EStopOK AND GuardClosed;
END_PROGRAM

prompt:
Линия фасовки PK-801. Датчик ProductSensor — импульс на каждую бутылку.

Реализуй PROGRAM ProductionCounter.

Входы:
  ProductSensor : BOOL;
  ResetBatch : BOOL;
  BatchTarget : INT := 1000.

Выходы:
  BatchCount : INT;
  BatchComplete : BOOL;
  TotalCount : INT — накопительный счёт (не сбрасывается ResetBatch).

R_TRIG на ProductSensor → CTU (PV=BatchTarget, R=ResetBatch).
BatchCount := Counter.CV, BatchComplete := Counter.Q.
TotalCount инкрементировать на каждом фронте датчика.

code:
PROGRAM ProductionCounter
VAR_INPUT
    ProductSensor : BOOL;
    ResetBatch    : BOOL;
    BatchTarget   : INT := 1000;
END_VAR
VAR_OUTPUT
    BatchCount    : INT;
    BatchComplete : BOOL;
    TotalCount    : INT;
END_VAR
VAR
    SensorEdge : R_TRIG;
    Counter    : CTU;
END_VAR

SensorEdge(CLK := ProductSensor);
Counter(CU := SensorEdge.Q, R := ResetBatch, PV := BatchTarget);

BatchCount := Counter.CV;
BatchComplete := Counter.Q;

IF SensorEdge.Q THEN
    TotalCount := TotalCount + 1;
END_IF;
END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    Enable     : BOOL;
    RawInput   : REAL;
    WindowSize : INT;
END_VAR
VAR_OUTPUT
    Filtered : REAL;
END_VAR
VAR
    Buffer        : ARRAY[0..9] OF REAL;
    Head          : INT := 0;
    Count         : INT := 0;
    Sum           : REAL := 0.0;
    EffectiveSize : INT := 1;
    Initialized   : BOOL := FALSE;
END_VAR

IF NOT Enable THEN
    Count := 0;
    Head := 0;
    Sum := 0.0;
    Filtered := 0.0;
    Initialized := FALSE;
ELSE
    IF NOT Initialized THEN
        Initialized := TRUE;
        EffectiveSize := WindowSize;
        IF EffectiveSize < 1 THEN
            EffectiveSize := 1;
        ELSIF EffectiveSize > 10 THEN
            EffectiveSize := 10;
        END_IF;
    END_IF;

    IF Count < EffectiveSize THEN
        Sum := Sum + RawInput;
        Buffer[Head] := RawInput;
        Head := (Head + 1) MOD EffectiveSize;
        Count := Count + 1;
    ELSE
        Sum := Sum - Buffer[Head] + RawInput;
        Buffer[Head] := RawInput;
        Head := (Head + 1) MOD EffectiveSize;
    END_IF;

    IF Count > 0 THEN
        Filtered := Sum / INT_TO_REAL(Count);
    ELSE
        Filtered := 0.0;
    END_IF;
END_IF;
END_FUNCTION_BLOCK
